			int wordIndex = groupId >>> 6;
			if (wordIndex >= factDerivedGroupWords.length) {
				factDerivedGroupWords = Arrays.copyOf(factDerivedGroupWords, wordIndex + 1);
			}
			long bit = 1L << groupId;
